  ngOnDestroy() {
    if (this.identityVerificationSubscription) {
      this.identityVerificationSubscription.unsubscribe();
    }
    if (this.resetButtonResetTimer) {
      clearTimeout(this.resetButtonResetTimer);
    }
  }
  ngOnInit() {
  }
  verifyIdentity(cspType) {
    this.loading = true;
    let identityVerificationObservable;
    if (this.configService.systemConfig$.connectMode == ConnectMode.Websocket) {
      identityVerificationObservable = this.fastenService.verificationWithWebsocket(cspType);
    } else {
      identityVerificationObservable = this.fastenService.verificationWithPopup(cspType);
    }
    this.identityVerificationSubscription = identityVerificationObservable.subscribe((result) => {
      this.loading = false;
      if (result?.vault_auth_finish_response?.has_verified_identity && result?.vault_auth_finish_response?.verified_identity_csp_type) {
        this.logger.info("setting verified identity csp_type csp type to", result.vault_auth_finish_response.verified_identity_csp_type);
        this.configService.vaultProfileConfig = {
          verifiedIdentityCspType: result.vault_auth_finish_response.verified_identity_csp_type,
          verifiedIdentityPatientDemographics: result.vault_auth_finish_response.verified_identity_patient_demographics
        };
      } else {
        this.configService.vaultProfileConfig = {
          verifiedIdentityCspType: cspType
        };
      }
      this.logger.info("verification result", result);
      this.router.navigateByUrl("dashboard");
    }, (err) => {
      this.loading = false;
      this.logger.error("verification error", err);
      try {
        var errData = JSON.parse(err.message);
        this.logger.debug("error_name", errData.error, "error_description", errData.error_description);
        if (errData.error == "timeout") {
          this.router.navigate(["/auth/identity/verification/error"], { queryParams: { "error": "timeout", "error_description": "timed out waiting for notification from popup" } });
        } else {
          this.router.navigate(["/auth/identity/verification/error"], { queryParams: { "error": errData.error, "error_description": errData.error_description } });
        }
      } catch (e2) {
        this.logger.error("Error parsing error response", e2);
        this.logger.error("original verification error", typeof err, err);
        this.router.navigate(["/auth/identity/verification/error"], { queryParams: { "error": "unknown", "error_description": "An unknown error occurred" } });
      }
      return;
    });
  }
  toggleResetMenu() {
    this.isResetMenuOpen = !this.isResetMenuOpen;
  }
  onResetConnections() {
    this.isResetMenuOpen = false;
    if (this.resetButtonState === "loading") {
      return;
    }
    this.setResetButtonState("loading");
    this.fastenService.revokeVaultProfileConnections().subscribe({
      next: () => {
        this.logger.info("Reset vault profile connections for test mode");
        this.setResetButtonState("success");
      },
      error: (error2) => {
        this.logger.error("Failed to reset vault profile connections", error2);
        this.setResetButtonState("error");
      }
    });
  }
  setResetButtonState(state) {
    if (this.resetButtonResetTimer) {
      clearTimeout(this.resetButtonResetTimer);
      this.resetButtonResetTimer = void 0;
    }
    this.resetButtonState = state;
    if (state === "success" || state === "error") {
      this.resetButtonResetTimer = setTimeout(() => {
        this.resetButtonState = "idle";
      }, 1600);
    }
  }
  closeResetMenu() {
    this.isResetMenuOpen = false;
  }
